```python
def bubble_sort(NUMBERS):
    N = len(NUMBERS)
    for I in range(N):
        for J in range(0, N-I-1):
            if NUMBERS[J] > NUMBERS[J+1]:
                NUMBERS[J], NUMBERS[J+1] = NUMBERS[J+1], NUMBERS[J]
    return NUMBERS

def quick_sort(NUMBERS):
    if len(NUMBERS) <= 1:
        return NUMBERS
    else:
        PIVOT = NUMBERS[0]
        LESS_THAN_PIVOT = [X for X in NUMBERS[1:] if X <= PIVOT]
        GREATER_THAN_PIVOT = [X for X in NUMBERS[1:] if X > PIVOT]
        return quick_sort(LESS_THAN_PIVOT) + [PIVOT] + quick_sort(GREATER_THAN_PIVOT)

def merge_sort(NUMBERS):
    if len(NUMBERS) <= 1:
        return NUMBERS
    MID = len(NUMBERS) // 2
    LEFT_HALF = merge_sort(NUMBERS[:MID])
    RIGHT_HALF = merge_sort(NUMBERS[MID:])
    return merge(LEFT_HALF, RIGHT_HALF)

def merge(LEFT, RIGHT):
    RESULT = []
    I = J = 0
    while I < len(LEFT) and J < len(RIGHT):
        if LEFT[I] < RIGHT[J]:
            RESULT.append(LEFT[I])
            I += 1
        else:
            RESULT.append(RIGHT[J])
            J += 1
    RESULT.extend(LEFT[I:])
    RESULT.extend(RIGHT[J:])
    return RESULT

# Example usage:
NUMBERS = [64, 34, 25, 12, 22, 11, 90]

print("Bubble Sort:", bubble_sort(NUMBERS.copy()))
print("Quick Sort:", quick_sort(NUMBERS.copy()))
print("Merge Sort:", merge_sort(NUMBERS.copy()))
```

